var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"겨우 세 명인데 뭐하는 거야! 똑바로 안 해!?","JPN":"たった3人しかいねえのに、何してんだ！　ちゃんとやれ！！","ENG":"What are you doing?! There are only three of them! Keep it together!","TWN":"他們才三個人而已！給我認真一點！！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"이, 이건 얘기가 다르잖아요, 형님!","JPN":"こ、これは話が違うっしょ、兄貴！","ENG":"Th-this isn't what I signed up for!","TWN":"這跟說好的不一樣啊！大哥！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"분명히 뜨내기 태스크포스라고……!","JPN":"確かにわか作りのタスクフォースだって……！","ENG":"I thought they were some rookie TASKFORCE–?!","TWN":"你不是說他們是三流特遣勢力……！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"으악! 내 눈!!","JPN":"うわっ！　目が！！","ENG":"Aargh! My eye!!","TWN":"啊啊！我的眼睛！！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나원, 저것들은 양심도 없나?","JPN":"まったく、あいつら良心ってものがないのかね？","ENG":"Egh, don't they feel any shame?","TWN":"那些傢伙的良心不會痛嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"신나게 실탄 쏘던 것들이 어딜 모의탄 맞고 엄살이야?","JPN":"実弾撃ってたくせに、模擬弾に当たって騒ぐなんてさ。","ENG":"They were shooting bullets at us, and now they're crying about being hit by rubber bullets?","TWN":"自己開槍開得那麼開心，被漆彈打到而已在那邊哀哀叫？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어차피 우리 목표는 수송기 탈환이에요. 일일이 상대해줄 필요 없어요.","JPN":"私たちの狙いは輸送船の奪還よ。いちいち相手してあげる必要なんかないわ。","ENG":"Our objective is to take back the aircraft. We don't need to deal with all of them.","TWN":"反正我們的目的是奪回運輸機，不需要見一個打一個。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"수송기까지 거의 다 왔어요!","JPN":"輸送船まであと少しです！","ENG":"I've almost reached the aircraft!","TWN":"快到運輸機了！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이제 탑승만 하면…….","JPN":"後は搭乗さえできれば……","ENG":"I just need to get on it...","TWN":"趕快搭上去就……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"잠깐! 장난은 거기까지다!","JPN":"待った！　お遊びはここまでだ！","ENG":"Hold it right there! Playtime's over!","TWN":"想得美！遊戲結束了！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……윽!","JPN":"……うっ！","ENG":"...Ngh!","TWN":"……唔！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"음? 저자는……?","JPN":"ん？　あの者は……？","ENG":"Hmm? That's...?","TWN":"嗯？他是……？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"후우, 생포하는 데 고생 좀 했지. 늙다리 주제에 주먹은 더럽게 매워 가지곤.","JPN":"ふう、生け捕りするのにちょっと苦労したぜ。老いぼれのくせに拳がやたら強くてな。","ENG":"Phew. Took longer than expected to capture him alive. He's got one mean punch for an old man.","TWN":"呼，費了一番勁才活捉到他，這老傢伙拳頭很硬呢！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"자, 아무튼 분위기 파악했으면 당장 수송기에서 떨어져.","JPN":"さあ、とにかく空気読んだなら、今すぐ輸送船から離れるんだ。","ENG":"Now, step away from the aircraft if you know what's good for you.","TWN":"總之，勸你們搞清楚狀況，趕快從運輸機上下來。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그렇지 않으면 이 노인네의……","JPN":"じゃないと、この老人の……","ENG":"Or else, this old man is gonna–","TWN":"否則這個老傢伙……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"으악! 무, 무슨 짓거리야! 아프잖아!","JPN":"うわっ！　な、何しやがる！　痛いじゃねえか！","ENG":"Aaargh! W-what was that for?! That hurt!","TWN":"呃啊！你，你做什麼！很痛欸！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시끄러워. 얼굴도 모르는 할배 데려다 놓고 어딜 개수작이야.","JPN":"うるさい。顔も知らないジジイ連れてきて、ふざけんなよ。","ENG":"Shut up. We don't even know that geezer. What are you trying to pull?","TWN":"吵死了你！我又不認識那個阿公，你把他帶來要做什麼？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"뭐? 이 노인네가 죽어도 상관없다는 거냐!?","JPN":"なにっ？　この老人が死んでもいいのか！？","ENG":"What? Then you're okay with me killing this old man?!","TWN":"什麼？我殺了他你也不在意嗎！？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"상관 있는 건 보험사겠지. 그 할배가 니들이랑 한통속인지 우리가 어떻게 알아?","JPN":"困るのは保険会社だろ？　そのジジイがあんたらとグルじゃないとどうしてわかる？","ENG":"The only ones not okay will be his insurance company. And who knows? Maybe he's on the same team as you.","TWN":"會在意的應該是保險公司吧？誰知道那個阿公是不是跟你們同一夥的？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"뭐 저런 개망나니가 다 있어!?","JPN":"何だと、この不良娘が！？","ENG":"You can't be serious right now!","TWN":"你是哪來的小王八蛋！？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치, 접선인이라는 사람이 혹시 저 할아버지에요?","JPN":"コーチ、受渡人というのはもしかしてあのお爺さんですか？","ENG":"Coach, this contact you were talking about. Is that him?","TWN":"教練，接應的人就是那個阿公嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……아닌 것 같네만?","JPN":"……違うと思うが。","ENG":"...I don't think so.","TWN":"……感覺應該不是？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카. 모르는 사람이래요, 쏴요.","JPN":"ライカ、知らない人だって。撃って。","ENG":"Laika. Coach doesn't know him. Shoot him.","TWN":"萊卡，開槍，他是陌生人。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"아악! 내 눈!!","JPN":"ぐわっ！　俺の目！！","ENG":"Aaagh! My eye!!","TWN":"啊啊！我的眼睛！！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이런 빌어먹을! 그만 좀 쏴!","JPN":"ちくしょう！　もうやめろ！","ENG":"Dammit! Stop shooting me!","TWN":"該死的！別再開啦！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"거기 당신! 당신이 이 쇳덩이를 수리해 달라고 의뢰한 거 아닌가?","JPN":"そこのお前さん！　お前さんがこの鉄の塊の修理を依頼したんだろ？","ENG":"Hey, you! Aren't you the one who requested this hunk of metal be repaired?","TWN":"就是你！是你委託我修理這塊廢鐵的不是嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"내가 이 수송기를 수리한 사람이야! 내 머리에 바람 구멍 냈다간 시동 걸 생각 말게!","JPN":"ワシがこの輸送船を修理した者だ！　ワシの頭に風穴が開いたら船は動かんぞ！","ENG":"I'm the guy who fixed her up! So don't you dare think about starting her engine when there's a hole between my eyes!","TWN":"我是修理這台運輸機的人！要是我的頭被打破洞，你就別想啟動它！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐야, 하청의 하청이라고?","JPN":"なんだ、下請けの下請け？","ENG":"What? A subcontract?","TWN":"什麼？是別人外包給你的？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"수작 부리지 마. 접선인이란 녀석은 어디 있는데?","JPN":"ふざけんなよ。接触する人って奴はどこにいるんだ？","ENG":"Like that's gonna fool anyone. So where's this contact of yours?","TWN":"少跟我來這套！那個接應的人在哪裡？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"내가 묻고 싶은 말이다! 사람을 납치하듯이 끌고 와서는……!","JPN":"それはワシのセリフだ！　人をさらうように連れてきやがって……！","ENG":"I could ask you the same thing! I was just kidnapped and–!","TWN":"我才想問咧！把人綁來這裡……！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"누, 누구야? 어떤 놈이 지시도 안 받고 폭탄을 터뜨렸어?","JPN":"だ、誰だ？　指示もないのに誰が爆弾を爆発させた？","ENG":"W-who was that? Who blew the charge without my orders?","TWN":"是誰？哪個傢伙不聽指令亂引爆炸彈？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_QM","text":{"KOREA":"괜찮습니다. 당신 지시는 입력해도 오류만 뱉을 거거든요.","JPN":"大丈夫です。あなたの指示は入力してもエラーを吐くだけですから。","ENG":"It's all right. Your orders will only come out as errors anyway.","TWN":"沒差，就算你輸入指令也只會出現錯誤。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"으, 으응?","JPN":"あ、ああ？","ENG":"H-huh?","TWN":"呃嗯？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_QM","text":{"KOREA":"코핀 컴퍼니 사장님 맞으시죠?","JPN":"コフィンカンパニーの社長ですね？","ENG":"Coffin Company's boss, I presume?","TWN":"你是科芬公司的老闆吧？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가…… 초원 양인가? 전달 받은 자료와 조금 달라 보이는데?","JPN":"君が……ナオ君か？　もらった資料とは少し違って見えるが。","ENG":"You're... Chowon? You look different from the records that I received.","TWN":"你是…… 初源？怎麼和我收到的資料看起來不太一樣？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"회장님께서 가급적 조용히 해결해 달라고 하셨으니까요.","JPN":"会長から、できるだけ目立たずに解決するように言われておりますので。","ENG":"The President asked to handle this as silently as possible.","TWN":"會長請我盡量低調處理。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"클리포트 게임 이후로 그룹 전체가 조사를 받고 있습니다.","JPN":"クリフォトゲーム以後、グループ全体が調査を受けています。","ENG":"The entire group is under investigation after the Qliphoth Game.","TWN":"因為逆卡巴拉遊戲之後，整個集團都在接受調查。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"뭐, 회장님은 무척 잘나신 분이라 그다지 걱정은 되지 않습니다만.","JPN":"まあ、会長はとても優秀な方なので、それほど心配はありませんが。","ENG":"The President is very talented, so I'm not worried about her at all.","TWN":"不過會長是個能力非常好的人，應該沒什麼好擔心的。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"소속이 뻔히 보이는 제복을 입고 와서 새로운 문제를 만들 필요는 없겠죠.","JPN":"どこの所属か丸わかりの制服を着て、新たな問題を作る必要はないでしょう。","ENG":"However, there is no need to create new problems by wearing a uniform of my affiliation.","TWN":"要是穿著顯眼的制服出現反而會引起騷動，何必呢？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"큭…! 이 자식들이! 감히 날 무시해!?","JPN":"くっ……！　このやろう！　俺を無視するのか！！","ENG":"Kgh...! You bastards! How dare you ignore me?!","TWN":"可惡…！你們這些傢伙！竟敢小看我！？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"여기는 감마! 문제가 생겼다! 지금 즉시 지원을 요청한다!","JPN":"こちら、ガンマ！　問題が発生した！　ただちに応援を要請する！","ENG":"This is Gamma! We got a problem here! I need immediate backup!","TWN":"我是伽馬！出了點問題！現在立刻派支援過來！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 감마! 문제가 생겼다! 지금 즉시 지원을 요청한다!</color>","JPN":"<color=#ffd34c>こちら、ガンマ！　問題が発生した！　ただちに応援を要請する！</color>","ENG":"<color=#ffd34c>This is Gamma! We got a problem here! I need immediate backup!</color>","TWN":"<color=#ffd34c>我是伽馬！出了點問題！現在立刻派支援過來！</color>"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"자, 잠깐? 어째서 네가…… 우리 무전기를……?","JPN":"ま、待てよ？　なんでお前が……俺らの無線機を……？","ENG":"W-what? How do you... have our comms...?","TWN":"什，什麼？你怎麼會……我們的無線電……？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"매복하고 있던 당신 동료들부터 정리하고 오느라 조금 늦어졌거든요.","JPN":"待ち伏せしていたあなたの仲間たちから処理して来たので、少々遅れました。","ENG":"It took me a while to arrive because I was busy taking care of your backup waiting to ambush us.","TWN":"我來的路上順便處理了一下你那些埋伏的夥伴，所以才會遲到。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"이제 남은 건 당신뿐이에요.","JPN":"残ったのはあなただけです。","ENG":"Now you're the only one left.","TWN":"現在只剩你還沒處理。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그, 그럼 그 거미 문양…… 설마……!","JPN":"じゃ、じゃあ、そのクモの模様……まさか……！","ENG":"Th-then that spider mark... It can't be...!","TWN":"那，那個螞蟻的圖案……難道你……！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"가, 가가, 가까이 오지 마! 다가오면 죽여 버리겠어!!","JPN":"く、くく、来るな！　こっちに来れば殺す！！","ENG":"S-s-stay away from me! Come any closer and I'll kill him!!","TWN":"走…走開…不要過來！再過來我就殺了你！！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"걱정 마세요. 저에겐 딱히 사람을 괴롭히는 취미가 없습니다.","JPN":"心配しないでください。私は別に人をいじめる趣味は持っていません。","ENG":"Don't worry. I don't take pleasure in torturing people.","TWN":"放心，我喜歡速戰速決。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그러니 얌전히 무기를 버리고 항복하세요.","JPN":"ですので、大人しく武器を捨てて降参してください。","ENG":"So throw down your weapon and surrender.","TWN":"你只要棄械投降，我就不會為難你。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"하, 항복합니다! 매달지만 말아 주세요! 제발 부탁입니다!","JPN":"こ、降参します！　吊るさないでください！　どうかお願いです！","ENG":"I-I surrender! Please don't hang me! PLEASE!!","TWN":"我，我投降！拜託放我一馬，不要殺我！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저 용병 언니, 분위기가 무지 무섭네요…….","JPN":"あの傭兵のお姉さん、なんだか怖い雰囲気が漂ってますね……","ENG":"That mercenary girl, she's scary, isn't she...?","TWN":"那個傭兵姊姊，感覺殺氣騰騰的欸……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"하지만 소대장님도 코핀의 도살마녀라고 불릴 만큼 살벌하신 분!","JPN":"でも、小隊長もコフィンの屠殺魔女と呼ばれるほどに殺伐とした方！","ENG":"But Commander is also scary! Enough so to be called the slaughtering witch!","TWN":"不過說到殺氣，我們小隊長也不輸人的，她可是科芬的魔女呢！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이 압력을 견뎌야만 어엿한 펜릴 소대원이 될 수 있는 거군요! 그렇죠, 사장님?","JPN":"この圧に耐えないと、立派な小隊員にはなれませんよね！　ね？　社長！","ENG":"I'll have to endure this pressure in order to become a proper member of Fenrir Squad! Right, Boss?","TWN":"必須能夠承受這樣的壓力，才有資格成為芬里爾小隊的一員！對吧，老闆？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그 별명 소대장 앞에선 쓰지 말게.","JPN":"そのあだ名は小隊長の前では出さない方がいい。","ENG":"I'd advise you not to use that nickname in front of your commander.","TWN":"千萬不要在小隊長面前那樣稱呼她。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇지. 좋은 자세야.","JPN":"よし。その意気だ。","ENG":"Correct. Props to you.","TWN":"沒錯，認知正確。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"거미라… 진짜 저걸 달고 다니는 사람이 있었구나.","JPN":"クモか……マジであれをつけてる人いたんだ。","ENG":"A spider...? So there really are people who carry that mark.","TWN":"螞蟻…原來是真有其人。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"호기심은 나중에 풀어요, 라이카.","JPN":"好奇心を満足させるのは後にして、ライカ。","ENG":"Satisfy your curiosity later, Laika.","TWN":"把你的好奇心先收起來，萊卡。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"경기 시작까지 얼마 안 남았어요, 코치! 어서 출발해야 해요!","JPN":"試合開始まで時間がありません、コーチ！　早く出発しないと！","ENG":"Our match is about to start, Coach! We need to get going!","TWN":"比賽就快開始了，教練！要趕快出發了！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};